            {"id": "display", "type": "concept", "label": "Display (.toDate, .toISOString, .unix)", "summary": ".toDate() → JS Date, .toISOString(), .valueOf() → ms timestamp, .unix() → seconds.", "difficulty": 1, "tags": ["display"]},
            {"id": "query", "type": "concept", "label": "Query (.isBefore, .isAfter, .isSame)", "summary": "Compare dates: .isBefore(other), .isAfter(other), .isSame(other, 'month').", "difficulty": 1, "tags": ["compare"]},
            {"id": "diff", "type": "function", "label": ".diff()", "summary": ".diff(other, 'day') returns numeric difference in given unit.", "difficulty": 2, "tags": ["compare"]},
            {"id": "plugins", "type": "concept", "label": "Plugins (extend)", "summary": "dayjs.extend(plugin) adds functionality: relativeTime, utc, timezone, duration, isBetween, weekday.", "difficulty": 2, "tags": ["plugins", "common"]},
            {"id": "utc", "type": "concept", "label": "UTC & Timezone Plugin", "summary": "dayjs.extend(utc); dayjs.extend(timezone). Use .utc() and .tz('America/New_York').", "difficulty": 2, "tags": ["timezone"]},
            {"id": "locale", "type": "concept", "label": "Locale (i18n)", "summary": "import 'dayjs/locale/fr'; dayjs.locale('fr'). Affects .format() day/month names.", "difficulty": 2, "tags": ["i18n"]},
