            {"id": "resize", "type": "function", "label": ".resize(width, height, options)", "summary": "Resize image. fit: cover/contain/fill/inside/outside. withoutEnlargement, position.", "difficulty": 1, "tags": ["transform", "common"]},
            {"id": "format", "type": "concept", "label": "Output Format (.jpeg, .png, .webp, .avif)", "summary": ".jpeg({quality:80}), .png(), .webp(), .avif(), .tiff(), .gif() — set output format and options.", "difficulty": 1, "tags": ["output", "common"]},
            {"id": "composite", "type": "function", "label": ".composite(overlays)", "summary": "Overlay images: watermarks, text, shape layers. Each overlay has input, gravity/top/left.", "difficulty": 2, "tags": ["composite"]},
